import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.BZO4qERu.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"PaperSeek","text":"LLM based Literature Search Agent","tagline":"用自然语言发起文献检索，自动迭代查询、扩展引用、排序结果，并导出可复核的候选论文列表。","image":{"src":"/paperseek-mark.png","alt":"PaperSeek"},"actions":[{"theme":"brand","text":"进入在线体验","link":"https://www.paperseek.xyz/"},{"theme":"alt","text":"阅读开源版手册","link":"/user-manual"},{"theme":"alt","text":"在线体验版说明","link":"/online-demo"},{"theme":"alt","text":"GitHub 仓库","link":"https://github.com/MingfengHong/paperseek"}]},"features":[{"title":"自然语言检索","details":"输入中文或英文研究问题，由 LLM 生成适合 OpenAlex、arXiv、Semantic Scholar、PubMed、Google Scholar、计算机顶会、Crossref 或 WoS Starter 的检索查询。"},{"title":"可观察工作流","details":"实时查看查询生成、数据源请求、检索式调整、结果排序、引用扩展和系统日志；排序阶段会拆分显示多路召回、embedding、RRF、LLM 批量打分和摘要补全等子步骤。"},{"title":"学科领域限制","details":"可在 Research Question 下方选择数据源和 Source Filter；OpenAlex、WoS、arXiv 使用原生硬过滤，其它数据源使用领域文本提示辅助 LLM 构建检索式。"},{"title":"中英文界面","details":"Web UI 支持 EN / 中文切换；在线版和开源自托管版使用一致的主要交互结构。"},{"title":"引用扩展与图谱","details":"基于 OpenAlex 扩展高匹配论文的参考文献和被引论文，并用箭头展示引用方向。"},{"title":"可复核导出","details":"在 Results 页面筛选、勾选、排序论文，导出包含元数据和评分理由的 CSV；系统会至少保留前 50 条结果，并在高分候选更多时展示全部 5 分及以上论文。"},{"title":"Agent 与 MCP 集成","details":"可复制自包含 Skill，或安装 paperseek[mcp] 启动 stdio MCP Server，让支持 MCP 的 AI agent 调用检索、诊断和历史工具。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1783267649000}'),l={name:"index.md"};function o(n,e,s,p,d,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="选择你的入口" tabindex="-1">选择你的入口 <a class="header-anchor" href="#选择你的入口" aria-label="Permalink to &quot;选择你的入口&quot;">​</a></h2><p>PaperSeek 的社区文档分为两个主要入口：</p><ul><li><strong>开源自托管版</strong>：阅读 <a href="./user-manual">开源版完整用户手册</a>，适合本地运行、Docker/VPS/ModelScope 创空间部署、配置自己的 LLM Key、数据源 Key 和默认 Discipline Fields。</li><li><strong>在线体验版</strong>：阅读 <a href="./online-demo">在线体验版用户手册</a>，适合直接访问 <a href="https://www.paperseek.xyz/" target="_blank" rel="noreferrer">paperseek.xyz</a> 试用完整 Web UI。在线版支持 PaperSeek Service、Third-party Service（ModelScope、OpenRouter、Hugging Face）和 Bring your own Key / BYOK 三种模式，并提供与自托管版一致的源特定过滤逻辑；登录和第三方授权会影响 PaperSeek Service、Third-party Service 与云端历史。</li><li><strong>Agent 集成</strong>：用户手册中的 <a href="./user-manual#agent-skill">Agent Skill</a> 和 <a href="./user-manual#mcp-server">MCP Server</a> 章节说明如何把 PaperSeek 接入支持 Skill 或 MCP 的 AI agent。</li></ul><p>部署 Docker、Docker Compose、Vercel 或 ModelScope 创空间时，阅读 <a href="./deployment">部署指南</a>。</p><h2 id="社区维护方式" tabindex="-1">社区维护方式 <a class="header-anchor" href="#社区维护方式" aria-label="Permalink to &quot;社区维护方式&quot;">​</a></h2><p>文档源码保存在 <code>main</code> 分支的 <code>docs/</code> 目录。GitHub Actions 构建后会把静态产物发布到 <code>gh-pages</code> 分支。<code>gh-pages</code> 只是 GitHub Pages 发布分支，不作为社区开发分支。</p>',6)])])}const m=t(l,[["render",o]]);export{g as __pageData,m as default};
